d_sim_ermod_sigemax |>
  ggplot(aes(x = exposure, y = response_1)) +
  # Emax model curve
  geom_vline(
    xintercept = ec50_mean,
    linetype = "dashed",
    color = "deepskyblue"
  ) +
  geom_ribbon(
    mapping = aes(
      y = .epred,
      ymin = .epred.lower,
      ymax = .epred.upper
    ),
    alpha = 0.3,
    fill = "deepskyblue"
  ) +
  geom_line(
    mapping = aes(y = .epred),
    color = "deepskyblue"
  ) +
  # Observed data
  geom_point(
    data = d_sim_emax,
    color = "grey"
  ) +
  # Prediction at the specified doses
  geom_point(
    data = d_sim_new_conc,
    mapping = aes(y = .epred),
    color = "tomato",
    size = 3
  ) +
  geom_errorbar(
    data = d_sim_new_conc,
    mapping = aes(
      y = .epred,
      ymin = .epred.lower,
      ymax = .epred.upper
    ),
    width = 1,
    color = "tomato"
  ) +
  coord_cartesian(ylim = c(7, 21)) +
  scale_fill_brewer(palette = "Greys") +
  labs(
    title = "Sigmoidal E~max~ model predictions at new exposure levels",
    caption = paste(
      "vertical dashed line: estimated EC~50~ value",
      "area: 95% credible interval",
      sep = "<br>"
    )
  ) +
  theme(
    plot.title = ggtext::element_markdown(),
    plot.caption = ggtext::element_markdown()
  )
